<span class="line">    <span class="token property">&quot;reply&quot;</span><span class="token operator">:</span> <span class="token string">&quot;def quick_sort(arr):\\n    if len(arr) &lt;= 1:\\n        return arr\\n    pivot = arr[len(arr) // 2]\\n    left = [x for x in arr if x &lt; pivot]\\n    middle = [x for x in arr if x == pivot]\\n    right = [x for x in arr if x &gt; pivot]\\n    return quick_sort(left) + middle + quick_sort(right)\\n\\n# 示例\\na = [3, 6, 8, 10, 1, 2, 1]\\nprint(quick_sort(a))  # 输出: [1, 1, 2, 3, 6, 8, 10]&quot;</span><span class="token punctuation">,</span></span>
