<span class="line">        <span class="token class-name">Qianfan</span> qianfan <span class="token operator">=</span> <span class="token keyword">new</span> <span class="token class-name">Qianfan</span><span class="token punctuation">(</span><span class="token string">&quot;YOUR_ACCESS_KEY&quot;</span><span class="token punctuation">,</span> <span class="token string">&quot;YOUR_SECRET_KEY&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span></span>
